const input = $items('Input Config / 输入配置')?.[0]?.json ?? {};
const rows = $input.all().map(item => item.json);
function cleanUrl(value) { return String(value || '').split('?')[0].replace(/\/$/, ''); }
function key(row) { return String(row.cid || row.data_id || row.website || row.title || '').toLowerCase().trim(); }
return rows.map((row, index) => {
  const website = cleanUrl(row.website);
  const emails = [row.email_1, row.email_2, row.email_3, row.email_4, row.all_emails].filter(Boolean).join(', ');
  const rating = Number(row.total_score || row.rating || 0);
  const reviewCount = Number(row.reviews_count || row.review_count || 0);
  let leadScore = 35;
  if (website) leadScore += 15;
  if (emails) leadScore += 25;
  if (row.phone) leadScore += 10;
  if (rating >= 4.5) leadScore += 10;
  if (reviewCount >= 100) leadScore += 10;
  if (rating > 0 && rating < 4) leadScore -= 15;
  leadScore = Math.max(0, Math.min(100, leadScore));
  const leadPriority = leadScore >= 80 ? 'hot' : leadScore >= 60 ? 'warm' : 'nurture';
  return { json: {
    workflow_kind: 'reputation_advanced', lead_key: key(row), index: index + 1,
    source_keyword: row.source_keyword || input.keyword || '', source_location: row.source_location || input.base_location || '',
    title: row.title || '', category: row.primary_category || row.all_categories || '', all_categories: row.all_categories || '',
    address: row.address || '', city: row.city || '', state: row.state || '', country: row.country || '', postal_code: row.postal_code || '',
    phone: row.phone || '', website, email: emails, rating, review_count: reviewCount, google_maps_url: row.url || '',
    lead_score: leadScore, lead_priority: leadPriority, crm_stage: leadPriority === 'hot' ? 'Qualified' : 'New',
    recommended_action: leadPriority === 'hot' ? 'Call today and send personalized email.' : leadPriority === 'warm' ? 'Send email and call within 48 hours.' : 'Add to nurture and enrich later.',
    company_summary: [row.title, row.primary_category, row.address, row.phone ? 'Phone: ' + row.phone : '', website ? 'Website: ' + website : ''].filter(Boolean).join(' | '),
    scraped_at: row.scraped_at || new Date().toISOString(), raw: row
  }};
});

const sourceItems = $items('Remove Duplicates / 去重').map(item => item.json);
return $input.all().map((item, index) => {
  const source = sourceItems[index] || sourceItems[0] || {};
  const body = item.json;
  const content = body?.choices?.[0]?.message?.content || '{}';
  const cleaned = String(content).replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim();
  let parsed = {};
  try { parsed = JSON.parse(cleaned); } catch (error) { parsed = { raw: content }; }
  return { json: { ...source, ai_persona: parsed.persona || '', ai_pain_point: parsed.pain_point || '', ai_pitch: parsed.pitch || '', ai_next_step: parsed.next_step || '', ai_risk: parsed.risk || '', ai_raw: parsed } };
});

